css: .cube {
    width: 200px;
    height: 200px;
    transform-style: preserve-3d;
    transition: transform 0.5s;
}
.face {
    position: absolute;
    width: 200px;
    height: 200px;
    border: 2px solid black;
    background-color: #333;
}

.red { background-color: #ff0000; }
.green { background-color: #00ff00; }
.blue { background-color: #0000ff; }

.rotation {
    transform: rotateX(45deg) rotateY(45deg);
}

js: var cube = document.querySelector('.cube');
var rotation = 0;
var interval = null;

// Add faces to the cube
for (let i = 0; i < 6; i++) {
    var face = document.createElement('div');
    face.classList.add('face');
    face.style.transform = getFaceTransform(i);
    cube.appendChild(face);
}

// Function to get face transform
function getFaceTransform(face) {
    var transform = 'rotateY(' + (face * 90) + 'deg) rotateX(90deg) translateZ(100px)';
    return transform;
}

// Function to rotate the cube
function rotateCube() {
    rotation += 1;
    cube.classList.add('rotation');
    interval = setTimeout(function() {
        cube.classList.remove('rotation');
        rotateCube();
    }, 500);
}

// Change the cube's color periodically
function changeColor() {
    var color = getRandomColor();

    // Change the color
    cube.children[0].classList.remove('red', 'green', 'blue');
    cube.children[0].classList.add(color);

    // Get a random color
    function getRandomColor() {
        var random = Math.floor(Math.random() * 3);
        if (random == 0) {
            return 'red';
        } else if (random == 1) {
            return 'green';
        } else {
            return 'blue';
        }
    }
}

// Start the rotation and color change intervals
rotateCube();
setInterval(changeColor, 2000);

